import React from "react"


class AddUser extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            firstname: "",
            info: "",
            job: ""
        }
    }
    render() {
        return (<form className="add-user-form" ref={(item) => this.addForm = item}>
            <input class="lol" placeholder="Имя" onChange={(e) => this.setState({firstname: e.target.value})} />
            <textarea placeholder="Информация о себе" onChange={(e) => this.setState({info: e.target.value})} />
            <input placeholder="Профессия" onChange={(e) => this.setState({job: e.target.value})} />
            <button type="button" onClick={() => this.props.onAdd({
                firstname: this.state.firstname,
                info: this.state.info,
                job: this.state.job
            })}>Добавить</button>
        </form>)
    }
}



export default AddUser
